<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Kanban Board</title>
<style>
  :root {
    --bg: #f4f5f7;
    --col-bg: #ebecf0;
    --col-bg-over: #dfe1e6;
    --card-bg: #ffffff;
    --text: #172b4d;
    --muted: #6b778c;
    --primary: #0052cc;
    --primary-hover: #0065ff;
    --danger: #de350b;
  }
  * { box-sizing: border-box; }
  body {
    margin: 0;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    background: var(--bg);
    color: var(--text);
  }
  .app {
    max-width: 1000px;
    margin: 40px auto;
    padding: 0 20px;
  }
  .topbar {
    display: flex;
    gap: 12px;
    margin-bottom: 24px;
  }
  #new-card {
    flex: 1;
    padding: 12px 14px;
    border: 1px solid #dfe1e6;
    border-radius: 6px;
    font-size: 15px;
    transition: border-color 0.2s, box-shadow 0.2s;
  }
  #new-card:focus {
    outline: none;
    border-color: var(--primary);
    box-shadow: 0 0 0 3px rgba(0,82,204,0.15);
  }
  #add-card {
    padding: 12px 20px;
    background: var(--primary);
    color: #fff;
    border: none;
    border-radius: 6px;
    font-size: 15px;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.2s;
  }
  #add-card:hover {
    background: var(--primary-hover);
  }
  .board {
    display: flex;
    gap: 20px;
    align-items: flex-start;
  }
  .column {
    flex: 1;
    background: var(--col-bg);
    border-radius: 10px;
    padding: 12px;
    min-height: 500px;
    display: flex;
    flex-direction: column;
    transition: background 0.2s;
  }
  .column.drag-over {
    background: var(--col-bg-over);
  }
  .col-header {
    font-weight: 600;
    font-size: 15px;
    margin-bottom: 12px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 4px 8px;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    color: var(--muted);
  }
  .count {
    background: #fff;
    color: var(--text);
    border-radius: 12px;
    padding: 2px 10px;
    font-size: 13px;
    font-weight: 700;
  }
  .card-container {
    flex: 1;
    display: flex;
    flex-direction: column;
    gap: 10px;
  }
  .card {
    background: var(--card-bg);
    border-radius: 6px;
    padding: 12px 14px;
    box-shadow: 0 1px 2px rgba(9,30,66,0.25);
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    cursor: grab;
    font-size: 14px;
    line-height: 1.4;
    transition: box-shadow 0.2s;
  }
  .card:hover {
    box-shadow: 0 2px 4px rgba(9,30,66,0.3);
  }
  .card.dragging {
    opacity: 0.5;
  }
  .card-title {
    word-break: break-word;
    margin-right: 8px;
    flex: 1;
  }
  .card-del {
    background: transparent;
    border: none;
    color: var(--muted);
    cursor: pointer;
    font-size: 18px;
    line-height: 1;
    padding: 0 4px;
    border-radius: 4px;
    flex-shrink: 0;
  }
  .card-del:hover {
    background: #ffebe6;
    color: var(--danger);
  }
</style>
</head>
<body>
  <div class="app">
    <div class="topbar">
      <input type="text" id="new-card" placeholder="Enter a task..." />
      <button id="add-card">Add Card</button>
    </div>
    <div class="board">
      <div class="column" id="col-todo">
        <div class="col-header">To Do <span class="count">0</span></div>
        <div class="card-container"></div>
      </div>
      <div class="column" id="col-doing">
        <div class="col-header">Doing <span class="count">0</span></div>
        <div class="card-container"></div>
      </div>
      <div class="column" id="col-done">
        <div class="col-header">Done <span class="count">0</span></div>
        <div class="card-container"></div>
      </div>
    </div>
  </div>

<script>
document.addEventListener('DOMContentLoaded', () => {
  const input = document.getElementById('new-card');
  const addBtn = document.getElementById('add-card');

  const columns = {
    todo: document.getElementById('col-todo'),
    doing: document.getElementById('col-doing'),
    done: document.getElementById('col-done')
  };

  let cards = [];
  const STORAGE_KEY = 'kanban-board-v1';

  function load() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) cards = JSON.parse(raw);
    } catch (e) {
      cards = [];
    }
  }

  function save() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(cards));
    } catch (e) {
      // ignore storage errors
    }
  }

  function render() {
    Object.values(columns).forEach(col => {
      col.querySelector('.card-container').innerHTML = '';
    });

    const counts = { todo: 0, doing: 0, done: 0 };

    cards.forEach(card => {
      const targetCol = columns[card.col] ? card.col : 'todo';
      const colEl = columns[targetCol];
      const container = colEl.querySelector('.card-container');

      const cardEl = document.createElement('div');
      cardEl.className = 'card';
      cardEl.draggable = true;
      cardEl.id = card.id;

      const title = document.createElement('span');
      title.className = 'card-title';
      title.textContent = card.title;
      cardEl.appendChild(title);

      const del = document.createElement('button');
      del.className = 'card-del';
      del.textContent = '×';
      del.title = 'Delete';
      del.addEventListener('click', () => {
        cards = cards.filter(c => c.id !== card.id);
        saveAndRender();
      });
      cardEl.appendChild(del);

      cardEl.addEventListener('dragstart', (e) => {
        e.dataTransfer.setData('text/plain', card.id);
        e.dataTransfer.effectAllowed = 'move';
        setTimeout(() => cardEl.classList.add('dragging'), 0);
      });

      cardEl.addEventListener('dragend', () => {
        cardEl.classList.remove('dragging');
        Object.values(columns).forEach(c => c.classList.remove('drag-over'));
      });

      container.appendChild(cardEl);
      counts[targetCol]++;
    });

    columns.todo.querySelector('.count').textContent = counts.todo;
    columns.doing.querySelector('.count').textContent = counts.doing;
    columns.done.querySelector('.count').textContent = counts.done;
  }

  function saveAndRender() {
    save();
    render();
  }

  addBtn.addEventListener('click', () => {
    const text = input.value.trim();
    if (!text) return;
    const id = 'card-' + Date.now() + '-' + Math.random().toString(36).slice(2, 11);
    cards.push({ id, title: text, col: 'todo' });
    input.value = '';
    saveAndRender();
  });

  input.addEventListener('keypress', (e) => {
    if (e.key === 'Enter') {
      addBtn.click();
    }
  });

  Object.entries(columns).forEach(([colName, colEl]) => {
    colEl.addEventListener('dragover', (e) => {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
      colEl.classList.add('drag-over');
    });

    colEl.addEventListener('dragleave', (e) => {
      if (!colEl.contains(e.relatedTarget)) {
        colEl.classList.remove('drag-over');
      }
    });

    colEl.addEventListener('drop', (e) => {
      e.preventDefault();
      colEl.classList.remove('drag-over');
      const id = e.dataTransfer.getData('text/plain');
      if (!id) return;
      const card = cards.find(c => c.id === id);
      if (card && card.col !== colName) {
        card.col = colName;
        saveAndRender();
      }
    });
  });

  load();
  render();
});
</script>
</body>
</html>
